WITH upd AS (
  UPDATE auth_sessions SET last_used_at = NOW()
  WHERE token = $1 AND expires_at > NOW()
  RETURNING user_id
)
SELECT user_id FROM upd;

parameters.jsCode:
const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('SSO: Auth check').first().json;
const srcItem = $('SSO: Auth check').first();
if (data && data.error) {
  return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }];
}
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id }, binary: (srcItem && srcItem.binary) || {} }];
